message:
refactor(tests): add TestContext helper to reduce test boilerplate

- Add fixture constants for common test data files
- Create TestContext struct that manages table/executor/result lifecycle
- Refactor 12 tests to use new helper pattern
- Reduces test file from 2086 to 1925 lines (-161 lines, -7.7%)

Pattern: var ctx: TestContext = undefined;
         try ctx.init(allocator, fixture);
         defer ctx.deinit();
         const result = try ctx.exec("SELECT ...");

